#include <stdio.h>
#include <stdlib.h>

int maxOffers;
int N, M;
int **offers;

void backtrack(int currentOffer, int acceptedOffers) {
    if (currentOffer == M) {
        if (acceptedOffers > maxOffers) {
            maxOffers = acceptedOffers;
        }
        return;
    }

    // Try to accept the current offer
    int valid = 1;
    for (int i = 0; i < currentOffer; i++) {
        for (int j = 1; j <= offers[currentOffer][0]; j++) {
            for (int k = 1; k <= offers[i][0]; k++) {
                if (offers[currentOffer][j] == offers[i][k]) {
                    valid = 0;
                    break;
                }
            }
            if (!valid) break;
        }
        if (!valid) break;
    }

    if (valid) {
        backtrack(currentOffer + 1, acceptedOffers + 1);
    }

    // Try not to accept the current offer
    backtrack(currentOffer + 1, acceptedOffers);
}

int main() {
    scanf("%d %d", &N, &M);
    offers = (int **)malloc(M * sizeof(int *));
    for (int i = 0; i < M; i++) {
        int Ki;
        scanf("%d", &Ki);
        offers[i] = (int *)malloc((Ki + 1) * sizeof(int));
        offers[i][0] = Ki;
        for (int j = 1; j <= Ki; j++) {
            scanf("%d", &offers[i][j]);
        }
    }

    maxOffers = 0;
    backtrack(0, 0);

    printf("%d\n", maxOffers);

    return 0;
}

