                    if (offers[currentOffer][j] == offers[i][k]) {
                        valid = false;
                        break;
                    }
                }
                if (!valid) break;
            }
            if (!valid) break;
        }

        if (valid) {
            backtrack(currentOffer + 1, acceptedOffers + 1);
        }

        // Try not to accept the current offer
        backtrack(currentOffer + 1, acceptedOffers);
    }

